import { createHash } from "node:crypto"; import { mkdir, readdir, readFile, rename, unlink, writeFile } from "node:fs/promises"; import path from "node:path";
interface Entry { createdAt:number; value:string; }
export const cacheKey=(value:unknown)=>createHash("sha256").update(JSON.stringify(value)).digest("hex");
export class CacheStore {constructor(private readonly dir:string,private readonly enabled:boolean,private readonly ttlSeconds:number,private readonly maxEntries:number){}private file(key:string){return path.join(this.dir,`${key}.json`);}async get(key:string){if(!this.enabled)return undefined;try{const entry=JSON.parse(await readFile(this.file(key),"utf8")) as Entry;if(Date.now()-entry.createdAt>=this.ttlSeconds*1000){await unlink(this.file(key));return undefined;}return entry.value;}catch{return undefined;}}async set(key:string,value:string){if(!this.enabled)return;await mkdir(this.dir,{recursive:true});const target=this.file(key),temp=`${target}.tmp`;await writeFile(temp,JSON.stringify({createdAt:Date.now(),value}),"utf8");await rename(temp,target);const files=(await readdir(this.dir)).filter(x=>x.endsWith(".json"));if(files.length>this.maxEntries){const entries=await Promise.all(files.map(async f=>({f,time:(await readFile(path.join(this.dir,f),"utf8")).includes("createdAt")?(JSON.parse(await readFile(path.join(this.dir,f),"utf8")) as Entry).createdAt:0})));for(const stale of entries.sort((a,b)=>a.time-b.time).slice(0,files.length-this.maxEntries))await unlink(path.join(this.dir,stale.f));}}}
